features.snippet:
inout wire PAD;
logic PAD_txen;
logic TX_IN;
always PAD = PAD_txen ? TX_IN : 1'bz;

module child(output logic RX_OUT, inout wire PAD);
  always_comb RX_OUT = PAD;
endmodule

module parent(inout wire PAD);
  child c(.PAD(PAD));
endmodule

export "DPI-C" task pad_bd_getPadOut;
task pad_bd_getPadOut(output bit value, output bit enable);
  enable = PAD_txen;
  value = PAD_txout;
endtask
